#include <iostream>
using namespace std;
int main(){
    int n; cin >> n;
    int pos=0,neg=0;
    for(int i=0;i<n;i++){ int x; cin>>x; if(x>0)pos++; else if(x<0)neg++; }
    cout << pos << " " << neg << endl;
    return 0;
}

